#include<bits/stdc++.h>
using namespace std;
int n,m;
char s[100010][21];
vector<int> mp[100010];
long long dis[100010][2];
void bfs(int x)
{
    queue<int> q;
    if(x==0)
    {
        q.push(1);
        dis[1][0]=0;
    }
    else
    {
        q.push(n);
        dis[n][1]=0;
    }
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i:mp[t])
        {
            if(dis[i][x]>dis[t][x]+1)
            {
                dis[i][x]=dis[t][x]+1;
                q.push(i);
            }
        }
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%s",s[i]+1);
        for(int j=1;j<=m;j++)
        {
            if(s[i][j]=='1')
            {
                mp[i].push_back(i+j);
            }
        }
    }
    memset(dis,0x3f,sizeof(dis));
    bfs(0);
    for(int i=1;i<=n;i++)
    {
        mp[i].clear();
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            if(s[i][j]=='1')
            {
                mp[i+j].push_back(i);
            }
        }
    }
    bfs(1);
    for(int i=2;i<n;i++)
    {
        long long ans=LLONG_MAX;
        for(int j=max(1,i-m+1);j<i;j++)
        {
            for(int k=1;k<=m;k++)
            {
                if(j+k>i&&s[j][k]=='1')
                {
                    ans=min(ans,dis[j][0]+dis[j+k][1]+1);
                }
            }
        }
        printf("%lld ",(ans>1e18?-1:ans));
    }
    return 0;
}
